{"cmd":"$ErrorActionPreference = 'Stop'
$out = (Resolve-Path .\outputs).Path
$sessionRoot = Join-Path $env:USERPROFILE '.codex\sessions'
$indexPath = Join-Path $env:USERPROFILE '.codex\session_index.jsonl'
$index = @{}
if (Test-Path -LiteralPath $indexPath) {
  Get-Content -LiteralPath $indexPath | ForEach-Object {
    if ($_.Trim()) {
      try {
        $row = $_ | ConvertFrom-Json
        if ($row.id) { $index[$row.id] = $row }
      } catch {}
    }
  }
}
$rows = Get-ChildItem -LiteralPath $sessionRoot -Recurse -File -Filter '*.jsonl' | Sort-Object FullName | ForEach-Object {
  $meta = $null
  try { $meta = (Get-Content -LiteralPath $_.FullName -TotalCount 1 | ConvertFrom-Json).payload } catch {}
  $sid = if ($meta.session_id) { $meta.session_id } elseif ($_.BaseName -match '([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})$') { $Matches[1] } else { '' }
  $idx = if ($sid -and $index.ContainsKey($sid)) { $index[$sid] } else { $null }
  [pscustomobject]@{
    session_id = $sid
    thread_name = if ($idx) { $idx.thread_name } else { '' }
    transcript_path = $_.FullName
    bytes = $_.Length
    last_write_time_local = $_.LastWriteTime.ToString('yyyy-MM-dd HH:mm:ss')
    session_timestamp_utc = if ($meta.timestamp) { $meta.timestamp } else { '' }
    cwd = if ($meta.cwd) { $meta.cwd } else { '' }
    originator = if ($meta.originator) { $meta.originator } else { '' }
    cli_version = if ($meta.cli_version) { $meta.cli_version } else { '' }
  }
}
$csv = Join-Path $out 'codex-session-transcripts.csv'
$rows | Export-Csv -NoTypeInformation -Encoding UTF8 -Path $csv
$byMonth = $rows | Group-Object { if ($_.session_timestamp_utc -match '^(\d{4}-\d{2})') { $Matches[1] } else { 'unknown' } } | Sort-Object Name | ForEach-Object { "- $($_.Name): $($_.Count)" }
$first = ($rows | Sort-Object session_timestamp_utc | Select-Object -First 1).session_timestamp_utc
$last = ($rows | Sort-Object session_timestamp_utc | Select-Object -Last 1).session_timestamp_utc
$totalMb = [math]::Round((($rows | Measure-Object bytes -Sum).Sum / 1MB), 2)
$outside = Get-Content -LiteralPath (Join-Path $out 'codex-transcript-content-scan.txt') | Where-Object { $_ -notlike 'C:\Users\ahazan2\.codex\sessions\*' }
$md = @()
$md += '# Local Codex Session Transcript Inventory'
$md += ''
$md += "Generated: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss zzz')"
$md += ''
$md += '## Result'
$md += ''
$md += "Found $($rows.Count) Codex session transcript JSONL files, totaling $totalMb MB."
$md += ''
$md += "Canonical transcript folder: ``$sessionRoot``"
$md += ''
$md += "Date range by transcript metadata: $first through $last."
$md += ''
$md += '## Counts By Month'
$md += ''
$md += $byMonth
$md += ''
$md += '## Scan Scope'
$md += ''
$md += 'Scanned local drive letters: C:\, D:\, E:\, G:\.'
$md += ''
$md += 'Did not crawl mapped NAS/network drives P:\, Q:\, R:\, S:\, T:\, U:\, Y:\, Z:\ because those are network mounts, not local machine storage, and they are very large.'
$md += ''
$md += 'Filename scan looked for: `rollout-*.jsonl`, `session_index.jsonl`, `history.jsonl`.'
$md += ''
$md += 'Content scan looked for Codex transcript marker: `"type":"session_meta"` in `*.jsonl` files.'
$md += ''
$md += '## Outside The Canonical Folder'
$md += ''
if ($outside.Count -eq 0) { $md += 'No Codex transcript files were found outside `C:\Users\ahazan2\.codex\sessions` on the scanned local drives.' } else { $md += $outside }
$md += ''
$md += '## Related Codex Files'
$md += ''
$md += '- `C:\Users\ahazan2\.codex\session_index.jsonl` contains the Codex thread index/title metadata.'
$md += '- `C:\Users\ahazan2\.codex\history.jsonl` contains Codex prompt/history metadata, but is not the full transcript store.'
$md += ''
$md += '## Catalog Files'
$md += ''
$md += '- `codex-session-transcripts.csv`: detailed transcript catalog with session id, thread name, path, size, timestamps, cwd, originator, and CLI version.'
$md += '- `codex-transcript-content-scan.txt`: raw content-marker scan results.'
$md += '- `codex-transcript-rg-scan.txt`: raw filename scan results.'
$summary = Join-Path $out 'codex-session-transcript-inventory.md'
$md | Set-Content -Encoding UTF8 -Path $summary
Get-Item -LiteralPath $csv,$summary,(Join-Path $out 'codex-transcript-content-scan.txt'),(Join-Path $out 'codex-transcript-rg-scan.txt') | Select-Object FullName,Length,LastWriteTime | Format-Table -AutoSize","shell":"powershell","yield_time_ms":10000,"max_output_tokens":20000}

